CREATE TABLE `wp_platform_request_responses` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `request_id` bigint(20) unsigned NOT NULL,
  `expert_user_id` bigint(20) unsigned NOT NULL,
  `response` varchar(20) NOT NULL,
  `counter_slots` longtext DEFAULT NULL,
  `note` text DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `price` decimal(10,2) DEFAULT 0.00,
  `proposed_start_iso` varchar(30) DEFAULT NULL,
  `duration_minutes` int(11) DEFAULT 60,
  PRIMARY KEY (`id`),
  KEY `idx_request` (`request_id`),
  KEY `idx_expert` (`expert_user_id`),
  KEY `request_id` (`request_id`)
) ENGINE=InnoDB AUTO_INCREMENT=138 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
